using System.Collections.Immutable; using Microsoft.CodeAnalysis; using Microsoft.CodeAnalysis.CSharp; using Xunit; namespace VisionaryCoder.Tooling.Generators.Tests; public sealed class StrongIdGeneratorTests { private static ImmutableArray<SyntaxTree> GetCompilation(string source, string attributeSource) => ImmutableArray.Create(CSharpSyntaxTree.ParseText(attributeSource), CSharpSyntaxTree.ParseText(source)); private static Compilation CreateCompilation(ImmutableArray<SyntaxTree> trees) { var references = AppDomain.CurrentDomain.GetAssemblies().Where(a => !a.IsDynamic && a.Location.Length > 0).Select(a => MetadataReference.CreateFromFile(a.Location)).Distinct().ToArray(); return CSharpCompilation.Create("GeneratorTest").AddReferences(references).AddSyntaxTrees(trees); } private static (Compilation, IEnumerable<string>) RunGenerator(string source, string attributeSource = "") { var defaultAttribute = "namespace Vc.Generators.Abstractions.Domain; [AttributeUsage(AttributeTargets.Struct)] public sealed class VcStrongIdAttribute : Attribute {}"; var attr = string.IsNullOrEmpty(attributeSource) ? defaultAttribute : attributeSource; var trees = GetCompilation(source, attr); var compilation = CreateCompilation(trees); var generator = new StrongIdGenerator(); var driver = CSharpGeneratorDriver.Create(generator); driver.RunGeneratorsAndUpdateCompilation(compilation, out var outputCompilation, out _); var sources = outputCompilation.SyntaxTrees.Skip(compilation.SyntaxTrees.Count()).Select(st => st.GetText().ToString()).ToList(); return (outputCompilation, sources); } [Fact] public void GeneratorExecutes() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.True(true); } [Fact] public void ProducesOutput() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.NotEmpty(s); } [Fact] public void ContainsValueProperty() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains("Value", s.First()); } [Fact] public void ContainsEquality() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains("Equals", s.First()); } [Fact] public void ContainsGetHashCode() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains("GetHashCode", s.First()); } [Fact] public void ContainsComparison() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains("==", s.First()); } [Fact] public void ContainsAutoGenHeader() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains("auto-generated", s.First()); } [Fact] public void ContainsNullableDirective() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Contains("#nullable", s.First()); } [Fact] public void IsDeterministic() { var (_, s1) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); var (_, s2) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain; [VcStrongId] public partial struct UserId {}"); Assert.Equal(s1.First(), s2.First()); } [Fact] public void PreservesNamespace() { var (_, s) = RunGenerator("using Vc.Generators.Abstractions.Domain; namespace Domain.Ids; [VcStrongId] public partial struct OrderId {}"); Assert.Contains("namespace Domain.Ids", s.First()); } }
